@import "tailwindcss";

@import url('https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,100..900;1,100..900&family=Mr+Dafoe&family=Orbitron:wght@400..900&display=swap');


.font-script {
  font-family: 'Mr Dafoe', cursive;
}
.font-orbitron {
  font-family: 'Orbitron', sans-serif;
}
.font-montserrat {
  font-family: 'Montserrat', sans-serif;
}

@theme {
  /* Cyberpunk Neon Colors */
  --color-neon-pink: #ff006e;
  --color-neon-pink-light: #ff1a8c;
  --color-neon-pink-dark: #cc0058;

  --color-neon-purple: #8b00ff;
  --color-neon-purple-light: #a020f0;
  --color-neon-purple-dark: #6600cc;

  --color-neon-blue: #00d9ff;
  --color-neon-blue-light: #1ae5ff;
  --color-neon-blue-dark: #00a8cc;

  --color-neon-magenta: #ff00ff;
  --color-neon-magenta-light: #ff33ff;
  --color-neon-magenta-dark: #cc00cc;

  /* Dark Navy Background */
  --color-dark-navy: #0a0e27;
  --color-dark-navy-light: #1a1e3f;
  --color-dark-navy-dark: #050711;

  /* Box Shadows */
  --shadow-neon-pink: 0 0 10px rgba(255, 0, 110, 0.5), 0 0 20px rgba(255, 0, 110, 0.3);
  --shadow-neon-purple: 0 0 10px rgba(139, 0, 255, 0.5), 0 0 20px rgba(139, 0, 255, 0.3);
  --shadow-neon-blue: 0 0 10px rgba(0, 217, 255, 0.5), 0 0 20px rgba(0, 217, 255, 0.3);
  --shadow-neon-magenta: 0 0 10px rgba(255, 0, 255, 0.5), 0 0 20px rgba(255, 0, 255, 0.3);

  /* Animations */
  --animate-pulse-slow: pulse 3s cubic-bezier(0.4, 0, 0.6, 1) infinite;
  --animate-glow: glow 2s ease-in-out infinite;
}

@keyframes glow {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}

/* Base Styles */
* {
  border-color: rgb(55 65 81);
}

body {
  background-color: var(--color-dark-navy);
  color: white;
  font-family: var(--font-geist-sans), system-ui, -apple-system, sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

html {
  scroll-behavior: smooth;
}

/* Glassmorphism Effects */
.glass {
  background: rgba(26, 30, 63, 0.2);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.glass-light {
  background: rgba(26, 30, 63, 0.1);
  backdrop-filter: blur(5px);
  -webkit-backdrop-filter: blur(5px);
}

.glass-medium {
  background: rgba(26, 30, 63, 0.2);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
}

.glass-heavy {
  background: rgba(26, 30, 63, 0.3);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
}

/* Neon Glow Effects */
.neon-glow-pink {
  box-shadow: var(--shadow-neon-pink);
}

.neon-glow-purple {
  box-shadow: var(--shadow-neon-purple);
}

.neon-glow-blue {
  box-shadow: var(--shadow-neon-blue);
}

.neon-glow-magenta {
  box-shadow: var(--shadow-neon-magenta);
}

